#include<bits/stdc++.h>
using namespace std;
int g(int a,int b){
	if(b==0)return a;
	return g(b,a%b);
}
int main()
{
	int x,y;
	cin>>x>>y;
	int xx=y*x;
	int cnt=0;
	for(int i=x;i<=y;i+=x){
		if(xx%i==0){
			int a=i,b=xx/i;

			int gcd=g(a,b);
//			cout<<a<<" "<<b<<" "<<gcd<<endl;
			a/=gcd;
			b/=gcd;
			if(a*b==y/x)cnt++;
		}
	}
	cout<<cnt;
}
